=========== local Sea1Islands = { { name = "Starter Island", level = 0 }, { name = "Jungle Island", level = 250 }, { name = "Desert Island", level = 750 }, { name = "Snow Island", level = 1500 }, { name = "Punch Island", level = 2500 }, { name = "Shibuya Station", level = 3000 }, { name = "Hollow Island", level = 5000 }, { name = "Sailor Island", level = 4500 }, { name = "Boss Island", level = 5000 }, { name = "Shinjuku Island", level = 6250 }, { name = "Slime Island", level = 8000 }, { name = "Dungeon Island", level = 5000 }, { name = "Academy Island", level = 9000 }, { name = "Judgement Island", level = 10000 }, { name = "Soul Dominion", level = 11000 }, { name = "Ninja Island", level = 12000 }, { name = "Lawless Island", level = 12000 }, { name = "Tower Island", level = 13000 }, { name = "World Island", level = 14000 }, } -- ============================================================ -- ILHAS SEA 2 -- ============================================================ local Sea2Islands = { { name = "Sea 2 Starter", level = 14500 }, { name = "Cosmic Island", level = 15000 }, { name = "Sea 2 Boss Hub", level = 15500 }, { name = "Guild Island", level = 16000 }, } local AllIslands = {} for _, v in ipairs(Sea1Islands) do table.insert(AllIslands, v.name) end for _, v in ipairs(Sea2Islands) do table.insert(AllIslands, v.name) end -- ============================================================ -- BOSSES -- ============================================================ local BossList = { -- Sea 1 "Knight", "Qin Shi", "Soul Reaper", "Corrupted Knight", "King of Heroes", "Blessed Maiden", "Moon Slayer", "Ice Queen", "Jinwoo", "Alucard", "Aizen", "Gilgamesh", "Saber Alter", "True Aizen", "Yamato", "Atomic", "Strongest Shinobi", -- Sea 2 "Cosmic Being", "Kraken", "Sea Serpent", "World Boss", } -- ============================================================ -- ESPADAS (Swords) -- ============================================================ local SwordList = { -- BГғВЎsicas "Dark Blade", "Katana", "Cursed Katana", -- Medianas "Ragna Blade", "Shadow Monarch Blade", "Abyss Edge", -- AvanГғВ§adas "Escanor Blade", "Atomic Blade", "Abyssal Empress", "Ice Queen Blade", "Dragon Goddess", "Great Mage", "True Aizen", "Yamato", "Anti-Magic Sword", -- Endgame "Shadow Monarch", "Cosmic Blade", } -- ============================================================ -- FRUTAS (Devil Fruits) -- ============================================================ local FruitList = { -- Naturais "Flame Fruit", "Ice Fruit", "Sand Fruit", "Dark Fruit", "Light Fruit", "Rumble Fruit", "Quake Fruit", -- Paramecia "Barrier Fruit", "String Fruit", "Op Fruit", -- Zoan "Phoenix Fruit", "Dragon Fruit", "Leopard Fruit", -- Mythical "Shadow Fruit", "Venom Fruit", "Gravity Fruit", } -- ============================================================ -- DUNGEONS -- ============================================================ local DungeonList = { "Shadow Dungeon", "Rune Dungeon", "Artifact Dungeon", "Infinite Tower", } -- ============================================================ -- CГғвҖңDIGOS ATIVOS (Maio 2026) -- ============================================================ local ActiveCodes = { "HUGEUPDATEWWW", "RAIDS", "DELAYCODENR1", "SAILORPIECE", "SEA2UPDATE", "DISCORD100K", "FREEGEMS2026", "RELEASE", "ALPHA", "BETA", } -- ============================================================ -- FUNГғвҖЎГғвҖўES AUXILIARES -- ============================================================ local function Notify(title, text, dur) WindUI:Notify({ Title = title, Content = text, Icon = "bell", Duration = dur or 4 }) end local function GetChar() return LP.Character end local function GetHRP() local c = GetChar() return c and c:FindFirstChild("HumanoidRootPart") end local function GetHum() local c = GetChar() return c and c:FindFirstChildOfClass("Humanoid") end local function TweenTo(cf, speed) local hrp = GetHRP() if not hrp then return end speed = speed or 80 local dist = (hrp.Position - cf.Position).Magnitude local dur = dist / speed local tw = TweenService:Create(hrp, TweenInfo.new(dur, Enum.EasingStyle.Linear), { CFrame = cf }) tw:Play() return tw end local function TeleportTo(cf) local hrp = GetHRP() if hrp then hrp.CFrame = cf end end local function GetLevel() pcall(function() local data = LP:FindFirstChild("leaderstats") or LP:FindFirstChild("Data") if data then local lv = data:FindFirstChild("Level") or data:FindFirstChild("Lv") if lv then return lv.Value end end end) return 0 end local function GetNearestEnemy(range) local hrp = GetHRP() if not hrp then return nil end range = range or 50 local best, bestDist = nil, range local folder = workspace:FindFirstChild("Enemies") or workspace:FindFirstChild("Mobs") or workspace for _, v in ipairs(folder:GetDescendants()) do if v:IsA("Model") and v:FindFirstChild("Humanoid") and v:FindFirstChild("HumanoidRootPart") then local hum = v:FindFirstChildOfClass("Humanoid") if hum and hum.Health > 0 then local dist = (v.HumanoidRootPart.Position - hrp.Position).Magnitude if dist < bestDist then bestDist = dist best = v end end end end return best end local function GetEnemiesInRange(range) local hrp = GetHRP() if not hrp then return {} end local list = {} for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v:FindFirstChild("Humanoid") and v:FindFirstChild("HumanoidRootPart") then local hum = v:FindFirstChildOfClass("Humanoid") if hum and hum.Health > 0 then local dist = (v.HumanoidRootPart.Position - hrp.Position).Magnitude if dist <= range then table.insert(list, v) end end end end return list end local function AttackEnemy(enemy) if not enemy or not enemy:FindFirstChild("HumanoidRootPart") then return end local hrp = GetHRP() if not hrp then return end hrp.CFrame = enemy.HumanoidRootPart.CFrame * CFrame.new(0, 3, 3) VU:CaptureController() VU:Button1Down(Vector2.new(851, 350)) task.wait(0.05) VU:Button1Up(Vector2.new(851, 350)) end local function PressKey(key) VIM:SendKeyEvent(true, key, false, game) task.wait(0.05) VIM:SendKeyEvent(false, key, false, game) end local function UseAllSkills() for _, k in ipairs({"Z","X","C","V","F"}) do PressKey(k) task.wait(0.1) end end local function GetPortalOnIsland(islandName) -- Tenta encontrar portais/spawns da ilha pelo nome for _, v in ipairs(workspace:GetDescendants()) do if (v.Name:lower():find(islandName:lower()) or islandName:lower():find(v.Name:lower())) and (v:IsA("BasePart") or v:IsA("Model")) then if v:IsA("BasePart") then return v.CFrame elseif v:IsA("Model") and v.PrimaryPart then return v:GetPivot() end end end return nil end -- ============================================================ -- TAB: HOME -- ============================================================ Tabs.HomeTab:Section({ Title = "ГўЛңВ ГҜВёпҝҪ DesplockHub ГўвӮ¬вҖқ Sailor Piece", TextXAlignment = "Left" }) Tabs.HomeTab:Paragraph({ Title = "DesplockHub", Desc = "VersГғВЈo 2.0 | Sea 1 & Sea 2 Completo\nFeito para a comunidade DesplockHub ГўпҝҪВӨГҜВёпҝҪ" }) Tabs.HomeTab:Paragraph({ Title = "Г°ЕёЕ’пҝҪ Discord", Desc = "Entre para atualizaГғВ§ГғВөes, suporte e mais!\ndiscord.gg/wCUv3GKxs" }) Tabs.HomeTab:Button({ Title = "Г°ЕёвҖңвҖ№ Copiar Link do Discord", Desc = "Copia discord.gg/wCUv3GKxs", Callback = function() setclipboard("https://discord.gg/wCUv3GKxs") Notify("DesplockHub", "Link do Discord copiado! Г°ЕёвҖңвҖ№", 3) end }) Tabs.HomeTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Guia RГғВЎpido", Desc = "1. VГғВЎ em Auto Farm ГўвҖ вҖҷ selecione a ilha ГўвҖ вҖҷ ative Start Farm\n2. Para ir ao Sea 2 ГўвҖ вҖҷ Misc ГўвҖ вҖҷ Auto Sea 2\n3. Boss Farm ГўвҖ вҖҷ escolha o boss ГўвҖ вҖҷ ative Auto Boss\n4. Dungeon ГўвҖ вҖҷ escolha o dungeon ГўвҖ вҖҷ ative Auto Dungeon\n5. Use Teleport para navegar entre ilhas rapidamente" }) -- Status do jogador local LevelParagraph = Tabs.HomeTab:Paragraph({ Title = "Г°ЕёвҖңЕ  Status", Desc = "Carregando..." }) task.spawn(function() while true do task.wait(2) pcall(function() local lv = GetLevel() local char = GetChar() local hum = char and char:FindFirstChildOfClass("Humanoid") local hp = hum and math.floor(hum.Health) or 0 local maxhp = hum and math.floor(hum.MaxHealth) or 0 LevelParagraph:SetDesc("Level: " .. lv .. " | HP: " .. hp .. "/" .. maxhp) end) end end) -- ============================================================ -- TAB: AUTO FARM -- ============================================================ Tabs.FarmTab:Section({ Title = "ГўЕЎвҖқГҜВёпҝҪ ConfiguraГғВ§ГғВЈo de Farm", TextXAlignment = "Left" }) -- Dropdown: Selecionar ilha local IslandDropdown = Tabs.FarmTab:Dropdown({ Title = "Г°ЕёпҝҪпҝҪГҜВёпҝҪ Selecionar Ilha", Desc = "Ilha onde o personagem vai farmar", Values = AllIslands, Value = "Starter Island", Callback = function(v) State.AutoFarmIsland = v end }) -- BotГғВЈo sugestГғВЈo automГғВЎtica de ilha por level Tabs.FarmTab:Button({ Title = "Г°ЕёвҖҷВЎ Sugerir Ilha pelo Meu Level", Desc = "Seleciona a melhor ilha para o seu nГғВӯvel atual", Callback = function() local lv = GetLevel() local best = Sea1Islands[1].name for i = #Sea1Islands, 1, -1 do if lv >= Sea1Islands[i].level then best = Sea1Islands[i].name break end end State.AutoFarmIsland = best IslandDropdown:SetValue(best) Notify("Auto Farm", "Ilha sugerida: " .. best, 4) end }) Tabs.FarmTab:Section({ Title = "Г°ЕёвҖқвҖһ Farm Loop", TextXAlignment = "Left" }) -- Toggle: Auto Quest Tabs.FarmTab:Toggle({ Title = "Г°ЕёвҖңЕ“ Auto Quest", Desc = "Aceita e completa quests automaticamente na ilha", Value = false, Callback = function(v) State.AutoQuest = v end }) -- Toggle: Kill Aura Tabs.FarmTab:Toggle({ Title = "Г°ЕёвҖҷВҘ Kill Aura", Desc = "Mata todos os inimigos ao redor automaticamente", Value = false, Callback = function(v) State.KillAura = v end }) -- Slider: Raio do Kill Aura Tabs.FarmTab:Slider({ Title = "Г°ЕёвҖңпҝҪ Raio Kill Aura", Value = { Min = 10, Max = 120, Default = 40 }, Step = 5, Callback = function(v) State.KillAuraRange = v end }) -- Toggle: Auto Farm Principal local FarmStatusPara = Tabs.FarmTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.FarmTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ START FARM", Desc = "Inicia o farm automГғВЎtico na ilha selecionada", Value = false, Callback = function(v) State.AutoFarm = v if v then FarmStatusPara:SetDesc("Г°ЕёЕёВў Farmando em: " .. State.AutoFarmIsland) Notify("Auto Farm", "Farm iniciado em: " .. State.AutoFarmIsland, 4) else FarmStatusPara:SetDesc("ГўЕЎВӘ Inativo") Notify("Auto Farm", "Farm parado.", 3) end end }) -- Loop Kill Aura task.spawn(function() while true do task.wait(0.15) if State.KillAura then pcall(function() local enemies = GetEnemiesInRange(State.KillAuraRange) for _, enemy in ipairs(enemies) do if enemy:FindFirstChild("HumanoidRootPart") then AttackEnemy(enemy) UseAllSkills() end end end) end end end) -- Loop Auto Farm task.spawn(function() while true do task.wait(0.3) if State.AutoFarm then pcall(function() -- Vai para a ilha local islandCF = GetPortalOnIsland(State.AutoFarmIsland) local hrp = GetHRP() if not hrp then return end if islandCF then local dist = (hrp.Position - islandCF.Position).Magnitude if dist > 200 then TweenTo(islandCF * CFrame.new(0, 5, 0)) task.wait(2) end end -- Aceita quest se habilitado if State.AutoQuest then pcall(function() local questNPC = workspace:FindFirstChild("QuestNPC") or workspace:FindFirstChild("Quest") if questNPC and questNPC:FindFirstChild("HumanoidRootPart") then local dist2 = (hrp.Position - questNPC.HumanoidRootPart.Position).Magnitude if dist2 > 20 then TweenTo(questNPC.HumanoidRootPart.CFrame * CFrame.new(0, 0, 5)) else VU:CaptureController() VIM:SendKeyEvent(true, "E", false, game) task.wait(0.2) VIM:SendKeyEvent(false, "E", false, game) end end end) end -- Mata inimigo mais prГғВіximo local enemy = GetNearestEnemy(80) if enemy and enemy:FindFirstChild("HumanoidRootPart") then TweenTo(enemy.HumanoidRootPart.CFrame * CFrame.new(0, 4, 4), 60) task.wait(0.2) AttackEnemy(enemy) UseAllSkills() end end) end end end) -- Anti AFK loop task.spawn(function() while true do task.wait(60) if State.AntiAFK then pcall(function() VU:CaptureController() VIM:SendKeyEvent(true, "W", false, game) task.wait(0.1) VIM:SendKeyEvent(false, "W", false, game) end) end end end) -- ============================================================ -- TAB: BOSS FARM -- ============================================================ Tabs.BossTab:Section({ Title = "ГўЛңВ ГҜВёпҝҪ Farm de Bosses", TextXAlignment = "Left" }) Tabs.BossTab:Dropdown({ Title = "Г°ЕёвҖҳВ№ Selecionar Boss", Values = BossList, Value = "Knight", Callback = function(v) State.AutoBossName = v end }) Tabs.BossTab:Paragraph({ Title = "Г°ЕёвҖңпҝҪ Locais dos Bosses", Desc = "Knight, Qin Shi, Soul Reaper ГўвҖ вҖҷ Boss Island\nJinwoo, Alucard ГўвҖ вҖҷ Sailor Island\nAizen ГўвҖ вҖҷ Hollow Island\nAtomic ГўвҖ вҖҷ Lawless Island\nStrongest Shinobi ГўвҖ вҖҷ Ninja Island\nCosmic Being, Kraken ГўвҖ вҖҷ Sea 2" }) local BossStatusPara = Tabs.BossTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.BossTab:Toggle({ Title = "Г°ЕёвҖқпҝҪ Loop Boss (repete apГғВіs matar)", Value = false, Callback = function(v) State.AutoBossLoop = v end }) Tabs.BossTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ AUTO BOSS FARM", Desc = "Vai atГғВ© o boss, mata e repete (se loop ativo)", Value = false, Callback = function(v) State.AutoBoss = v if v then BossStatusPara:SetDesc("Г°ЕёЕёВў CaГғВ§ando: " .. State.AutoBossName) else BossStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() while true do task.wait(0.5) if State.AutoBoss then pcall(function() local hrp = GetHRP() if not hrp then return end -- Procura o boss no workspace local boss = nil for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v.Name:lower():find(State.AutoBossName:lower()) and v:FindFirstChild("Humanoid") and v:FindFirstChild("HumanoidRootPart") and v:FindFirstChildOfClass("Humanoid").Health > 0 then boss = v break end end if boss and boss:FindFirstChild("HumanoidRootPart") then local bHRP = boss.HumanoidRootPart local dist = (hrp.Position - bHRP.Position).Magnitude BossStatusPara:SetDesc("Г°ЕёЕёВЎ Atacando: " .. State.AutoBossName .. " | HP: " .. math.floor(boss:FindFirstChildOfClass("Humanoid").Health)) if dist > 25 then TweenTo(bHRP.CFrame * CFrame.new(0, 5, 10), 80) task.wait(1) else AttackEnemy(boss) UseAllSkills() end else BossStatusPara:SetDesc("Г°ЕёвҖқВҙ Boss nГғВЈo encontrado ГўвӮ¬вҖқ aguardando spawn...") if not State.AutoBossLoop then State.AutoBoss = false BossStatusPara:SetDesc("ГўЕЎВӘ Inativo") end task.wait(3) end end) end end end) -- ============================================================ -- TAB: DUNGEON -- ============================================================ Tabs.DungeonTab:Section({ Title = "Г°ЕёпҝҪВ° Auto Dungeon", TextXAlignment = "Left" }) Tabs.DungeonTab:Dropdown({ Title = "Г°ЕёвҖқвҖҳ Selecionar Dungeon", Values = DungeonList, Value = "Shadow Dungeon", Callback = function(v) State.AutoDungeonType = v end }) Tabs.DungeonTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Como Funciona", Desc = "Shadow Dungeon ГўвҖ вҖҷ Dungeon Island (Lv 5000+)\nRune Dungeon ГўвҖ вҖҷ requer Rune Keys\nArtifact Dungeon ГўвҖ вҖҷ requer Artifact Keys\nInfinite Tower ГўвҖ вҖҷ Tower Island (ondas infinitas)" }) Tabs.DungeonTab:Paragraph({ Title = "Г°ЕёвҖқвҖҳ Obter Chaves de Dungeon", Desc = "Chaves dropam de bosses (Strongest Shinobi, Atomic)\nTroque Gems por chaves na loja de Shadow Island\nParticipar de raids no Boss Island tambГғВ©m dГғВЎ chaves" }) local DungeonStatusPara = Tabs.DungeonTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.DungeonTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ AUTO DUNGEON", Desc = "Vai para o dungeon e limpa automaticamente em loop", Value = false, Callback = function(v) State.AutoDungeon = v if v then DungeonStatusPara:SetDesc("Г°ЕёЕёВў Executando: " .. State.AutoDungeonType) Notify("Auto Dungeon", "Iniciando: " .. State.AutoDungeonType, 4) else DungeonStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() local wave = 0 while true do task.wait(0.5) if State.AutoDungeon then pcall(function() local hrp = GetHRP() if not hrp then return end -- Procura inimigos dentro do dungeon / torre local enemies = GetEnemiesInRange(150) if #enemies > 0 then wave = wave + 1 DungeonStatusPara:SetDesc("Г°ЕёЕёВў " .. State.AutoDungeonType .. " | Onda: " .. wave .. " | Inimigos: " .. #enemies) for _, enemy in ipairs(enemies) do if enemy:FindFirstChild("HumanoidRootPart") then TweenTo(enemy.HumanoidRootPart.CFrame * CFrame.new(0, 4, 4), 70) task.wait(0.15) AttackEnemy(enemy) UseAllSkills() end end else DungeonStatusPara:SetDesc("Г°ЕёЕёВЎ Aguardando inimigos/prГғВіxima onda...") task.wait(2) end end) else wave = 0 end end end) -- ============================================================ -- TAB: SWORDS (Espadas) -- ============================================================ Tabs.SwordTab:Section({ Title = "ГўЕЎвҖқГҜВёпҝҪ Farm de Espadas", TextXAlignment = "Left" }) Tabs.SwordTab:Dropdown({ Title = "Г°ЕёвҖ”ВЎГҜВёпҝҪ Selecionar Espada", Values = SwordList, Value = "Dark Blade", Callback = function(v) State.AutoSwordTarget = v end }) Tabs.SwordTab:Paragraph({ Title = "Г°ЕёвҖңпҝҪ Onde Farmar cada Espada", Desc = "Dark Blade / Katana ГўвҖ вҖҷ Starter Island (Loja)\nRagna Blade / Shadow Monarch ГўвҖ вҖҷ Boss Island (drops)\nAbyss Edge ГўвҖ вҖҷ Sailor Island (Jinwoo/Alucard)\nDragon Goddess / Great Mage ГўвҖ вҖҷ Sea 2\nAnti-Magic Sword ГўвҖ вҖҷ Punch Island (Crystal Defense)\nTrue Aizen ГўвҖ вҖҷ Hollow Island (Aizen boss)\nYamato ГўвҖ вҖҷ Lawless Island (Atomic)" }) local SwordStatusPara = Tabs.SwordTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.SwordTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ AUTO SWORD FARM", Desc = "Vai para o local correto e faz farm da espada selecionada", Value = false, Callback = function(v) State.AutoSword = v if v then SwordStatusPara:SetDesc("Г°ЕёЕёВў Farmando: " .. State.AutoSwordTarget) Notify("Sword Farm", "Buscando: " .. State.AutoSwordTarget, 4) else SwordStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) -- Mapa de bosses por espada local SwordBossMap = { ["Dark Blade"] = "Knight", ["Shadow Monarch Blade"]= "Jinwoo", ["Abyss Edge"] = "Alucard", ["True Aizen"] = "True Aizen", ["Yamato"] = "Atomic", ["Dragon Goddess"] = "Cosmic Being", ["Anti-Magic Sword"] = "Crystal Defense", ["Ragna Blade"] = "Soul Reaper", ["Escanor Blade"] = "Blessed Maiden", ["Atomic Blade"] = "Atomic", ["Abyssal Empress"] = "Blessed Maiden", ["Ice Queen Blade"] = "Ice Queen", ["Great Mage"] = "Cosmic Being", } task.spawn(function() while true do task.wait(0.5) if State.AutoSword then pcall(function() local targetBoss = SwordBossMap[State.AutoSwordTarget] or "Knight" -- Redireciona para a lГғВіgica de boss local hrp = GetHRP() if not hrp then return end local boss = nil for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v.Name:lower():find(targetBoss:lower()) and v:FindFirstChild("Humanoid") and v:FindFirstChildOfClass("Humanoid").Health > 0 then boss = v; break end end if boss and boss:FindFirstChild("HumanoidRootPart") then SwordStatusPara:SetDesc("Г°ЕёЕёВЎ Atacando boss para: " .. State.AutoSwordTarget) TweenTo(boss.HumanoidRootPart.CFrame * CFrame.new(0, 5, 8), 80) task.wait(0.5) AttackEnemy(boss) UseAllSkills() else SwordStatusPara:SetDesc("Г°ЕёвҖқВҙ Boss '" .. targetBoss .. "' nГғВЈo encontrado ГўвӮ¬вҖқ aguardando...") task.wait(3) end end) end end end) -- ============================================================ -- TAB: FRUITS (Devil Fruits) -- ============================================================ Tabs.FruitTab:Section({ Title = "Г°ЕёпҝҪЕҪ Devil Fruits", TextXAlignment = "Left" }) Tabs.FruitTab:Paragraph({ Title = "Г°ЕёвҖңпҝҪ Como obter Fruits", Desc = "Frutas spawnam aleatoriamente nas ilhas a cada ~20 min\nCompre na Fruit Dealer em Sailor Island com Gems\nDropam de World Bosses e Dungeons\nFrutas Mythical: muito raras ГўвӮ¬вҖқ use ESP de Frutas!" }) Tabs.FruitTab:Toggle({ Title = "Г°ЕёвҖҳпҝҪГҜВёпҝҪ ESP de Frutas", Desc = "Destaca frutas no mapa com marcadores visuais", Value = false, Callback = function(v) State.FruitEsp = v Notify("Fruit ESP", v and "ESP de Frutas ativado! Г°ЕёпҝҪЕҪ" or "ESP desativado.", 3) end }) Tabs.FruitTab:Toggle({ Title = "Г°ЕёпҝҪЖ’ Auto Teleport para Fruta", Desc = "Teleporta automaticamente quando uma fruta spawnar", Value = false, Callback = function(v) State.AutoFruit = v end }) Tabs.FruitTab:Toggle({ Title = "Г°ЕёпҝҪВҪГҜВёпҝҪ Auto Comer Fruta", Desc = "Come a fruta automaticamente ao pegar", Value = false, Callback = function(v) State.AutoEatFruit = v end }) -- ESP de frutas (labels visuais) task.spawn(function() while true do task.wait(1) if State.FruitEsp then pcall(function() for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v.Name:find("Fruit") and not v:FindFirstChild("_FruitESP") then local hrp = v:FindFirstChild("HumanoidRootPart") or v:FindFirstChildWhichIsA("BasePart") if hrp then local bb = Instance.new("BillboardGui", v) bb.Name = "_FruitESP" bb.Size = UDim2.new(0, 120, 0, 30) bb.AlwaysOnTop = true bb.StudsOffset = Vector3.new(0, 4, 0) bb.Adornee = hrp local lbl = Instance.new("TextLabel", bb) lbl.Size = UDim2.new(1, 0, 1, 0) lbl.BackgroundTransparency = 0.3 lbl.BackgroundColor3 = Color3.fromRGB(20, 0, 40) lbl.TextColor3 = Color3.fromRGB(255, 200, 0) lbl.Font = Enum.Font.GothamBold lbl.TextSize = 13 lbl.Text = "Г°ЕёпҝҪЕҪ " .. v.Name end elseif not State.FruitEsp then local esp = v:FindFirstChild("_FruitESP") if esp then esp:Destroy() end end end end) end end end) -- Auto grab fruit workspace.ChildAdded:Connect(function(child) if State.AutoFruit and child.Name:find("Fruit") then task.wait(0.3) pcall(function() local hrp = GetHRP() local fPart = child:FindFirstChildWhichIsA("BasePart") if hrp and fPart then hrp.CFrame = fPart.CFrame * CFrame.new(0, 2, 0) end if State.AutoEatFruit then task.wait(0.5) PressKey("E") end end) end end) -- ============================================================ -- TAB: HAKI -- ============================================================ Tabs.HakiTab:Section({ Title = "ГўЕЎВЎ Auto Haki", TextXAlignment = "Left" }) Tabs.HakiTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre o Haki", Desc = "Observation Haki ГўвҖ вҖҷ treina esquivando ataques\nArmament Haki ГўвҖ вҖҷ aumenta dano e defesa\nConqueror's Haki ГўвҖ вҖҷ habilidade especial de domГғВӯnio" }) Tabs.HakiTab:Toggle({ Title = "Г°ЕёвҖҳпҝҪГҜВёпҝҪ Auto Observation Haki", Desc = "Esquiva ataques automaticamente para treinar Obs Haki", Value = false, Callback = function(v) State.AutoObsHaki = v Notify("Haki", v and "Observation Haki ativado!" or "Desativado.", 3) end }) Tabs.HakiTab:Toggle({ Title = "Г°ЕёвҖәВЎГҜВёпҝҪ Auto Armament Haki", Desc = "MantГғВ©m o Armament Haki sempre ativo", Value = false, Callback = function(v) State.AutoArmHaki = v Notify("Haki", v and "Armament Haki ativado!" or "Desativado.", 3) end }) Tabs.HakiTab:Toggle({ Title = "Г°ЕёвҖҳвҖҳ Auto Conqueror's Haki", Desc = "Usa Conqueror's Haki automaticamente quando disponГғВӯvel", Value = false, Callback = function(v) State.AutoConqHaki = v end }) -- Haki loops task.spawn(function() while true do task.wait(0.5) pcall(function() if State.AutoArmHaki then -- Tenta ativar Armament Haki via tecla ou skill PressKey("G") -- tecla comum de Haki em jogos One Piece end if State.AutoConqHaki then PressKey("H") end end) end end) -- ============================================================ -- TAB: TELEPORT -- ============================================================ Tabs.TeleportTab:Section({ Title = "Г°ЕёвҖ”ВәГҜВёпҝҪ Teleporte ГўвӮ¬вҖқ Sea 1", TextXAlignment = "Left" }) for _, island in ipairs(Sea1Islands) do Tabs.TeleportTab:Button({ Title = "ГўЕЎвҖң " .. island.name, Desc = "Lv " .. island.level .. "+", Callback = function() pcall(function() -- Usa o sistema de portais do jogo local hrp = GetHRP() if not hrp then return end -- Tenta usar o portal do jogo (tecla E em cima do portal) local portal = GetPortalOnIsland(island.name) if portal then hrp.CFrame = portal * CFrame.new(0, 3, 0) task.wait(0.5) PressKey("E") task.wait(0.3) -- Confirma teleporte no menu VU:CaptureController() VU:Button1Down(Vector2.new(400, 300)) task.wait(0.1) VU:Button1Up(Vector2.new(400, 300)) end Notify("Teleport", "Indo para: " .. island.name, 3) end) end }) end Tabs.TeleportTab:Section({ Title = "Г°ЕёЕ’Е  Teleporte ГўвӮ¬вҖқ Sea 2", TextXAlignment = "Left" }) for _, island in ipairs(Sea2Islands) do Tabs.TeleportTab:Button({ Title = "ГўЕЎвҖң " .. island.name, Desc = "Lv " .. island.level .. "+", Callback = function() Notify("Teleport", "Indo para: " .. island.name .. " (Sea 2)", 3) pcall(function() local hrp = GetHRP() if not hrp then return end local portal = GetPortalOnIsland(island.name) if portal then hrp.CFrame = portal * CFrame.new(0, 3, 0) task.wait(0.5) PressKey("E") end end) end }) end -- ============================================================ -- TAB: ESP -- ============================================================ Tabs.EspTab:Section({ Title = "Г°ЕёвҖҳпҝҪГҜВёпҝҪ ESP / Rastreamento", TextXAlignment = "Left" }) Tabs.EspTab:Toggle({ Title = "Г°ЕёвҖҳВҘ ESP de Jogadores", Desc = "Mostra nomes e distГғВўncia dos outros jogadores", Value = false, Callback = function(v) State.EspPlayers = v end }) Tabs.EspTab:Toggle({ Title = "Г°ЕёЕҪпҝҪ ESP de BaГғВәs", Desc = "Destaca baГғВәs no mapa", Value = false, Callback = function(v) State.EspChests = v end }) Tabs.EspTab:Toggle({ Title = "Г°ЕёпҝҪЕҪ ESP de Frutas", Desc = "Destaca Devil Fruits no mapa", Value = false, Callback = function(v) State.FruitEsp = v end }) Tabs.EspTab:Toggle({ Title = "ГўЛңВ ГҜВёпҝҪ ESP de Bosses", Desc = "Destaca bosses e mostra HP", Value = false, Callback = function(v) State.EspBosses = v end }) -- ESP loop task.spawn(function() local espNum = math.random(100000, 999999) while true do task.wait(1) pcall(function() -- ESP Jogadores for _, plr in ipairs(Players:GetPlayers()) do if plr ~= LP and plr.Character then local head = plr.Character:FindFirstChild("Head") if head then local existing = head:FindFirstChild("_ESP_" .. espNum) if State.EspPlayers and not existing then local bb = Instance.new("BillboardGui", head) bb.Name = "_ESP_" .. espNum bb.Size = UDim2.new(0, 180, 0, 36) bb.AlwaysOnTop = true bb.StudsOffset = Vector3.new(0, 2.5, 0) bb.Adornee = head local lbl = Instance.new("TextLabel", bb) lbl.Size = UDim2.new(1,0,1,0) lbl.BackgroundTransparency = 0.3 lbl.BackgroundColor3 = Color3.fromRGB(0, 0, 60) lbl.TextColor3 = Color3.fromRGB(100, 200, 255) lbl.Font = Enum.Font.GothamBold lbl.TextSize = 12 elseif State.EspPlayers and existing then local hrp = GetHRP() local pHRP = plr.Character:FindFirstChild("HumanoidRootPart") if hrp and pHRP then local dist = math.floor((hrp.Position - pHRP.Position).Magnitude) local pHum = plr.Character:FindFirstChildOfClass("Humanoid") local hp = pHum and math.floor(pHum.Health) or 0 local lbl = existing:FindFirstChildOfClass("TextLabel") if lbl then lbl.Text = "Г°ЕёвҖҳВӨ " .. plr.Name .. "\nГўпҝҪВӨГҜВёпҝҪ " .. hp .. " | Г°ЕёвҖңпҝҪ " .. dist .. "m" end end elseif not State.EspPlayers and existing then existing:Destroy() end end end end -- ESP Bosses for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") then local hum = v:FindFirstChildOfClass("Humanoid") local hrpB = v:FindFirstChild("HumanoidRootPart") if hum and hrpB and hum.MaxHealth > 10000 then -- provГғВЎvel boss local existing = hrpB:FindFirstChild("_BossESP") if State.EspBosses and not existing then local bb = Instance.new("BillboardGui", hrpB) bb.Name = "_BossESP" bb.Size = UDim2.new(0, 200, 0, 40) bb.AlwaysOnTop = true bb.StudsOffset = Vector3.new(0, 5, 0) local lbl = Instance.new("TextLabel", bb) lbl.Size = UDim2.new(1,0,1,0) lbl.BackgroundTransparency = 0.3 lbl.BackgroundColor3 = Color3.fromRGB(60, 0, 0) lbl.TextColor3 = Color3.fromRGB(255, 100, 100) lbl.Font = Enum.Font.GothamBold lbl.TextSize = 12 elseif State.EspBosses and existing then local hrpMe = GetHRP() local lbl = existing:FindFirstChildOfClass("TextLabel") if lbl and hrpMe then local dist = math.floor((hrpMe.Position - hrpB.Position).Magnitude) lbl.Text = "ГўЛңВ ГҜВёпҝҪ " .. v.Name .. "\nГўпҝҪВӨГҜВёпҝҪ " .. math.floor(hum.Health) .. " | Г°ЕёвҖңпҝҪ " .. dist .. "m" end elseif not State.EspBosses and existing then existing:Destroy() end end end end -- ESP BaГғВәs for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("BasePart") and (v.Name:lower():find("chest") or v.Name:lower():find("bau")) then local existing = v:FindFirstChild("_ChestESP") if State.EspChests and not existing then local bb = Instance.new("BillboardGui", v) bb.Name = "_ChestESP" bb.Size = UDim2.new(0, 140, 0, 28) bb.AlwaysOnTop = true bb.StudsOffset = Vector3.new(0, 3, 0) local lbl = Instance.new("TextLabel", bb) lbl.Size = UDim2.new(1,0,1,0) lbl.BackgroundTransparency = 0.3 lbl.BackgroundColor3 = Color3.fromRGB(50, 35, 0) lbl.TextColor3 = Color3.fromRGB(255, 220, 0) lbl.Font = Enum.Font.GothamBold lbl.TextSize = 12 lbl.Text = "Г°ЕёЕҪпҝҪ " .. v.Name elseif not State.EspChests and existing then existing:Destroy() end end end end) end end) -- ============================================================ -- TAB: PLAYER -- ============================================================ Tabs.PlayerTab:Section({ Title = "Г°ЕёвҖңЕ  Stats", TextXAlignment = "Left" }) Tabs.PlayerTab:Dropdown({ Title = "Г°ЕёвҖңЛҶ Distribuir Stats em", Values = {"Sword", "Melee", "Fruit", "Gun", "Defense", "HP"}, Value = "Sword", Callback = function(v) State.StatChoice = v end }) Tabs.PlayerTab:Toggle({ Title = "ГўЕЎВЎ Auto Distribuir Stats", Desc = "Distribui pontos automaticamente na stat selecionada", Value = false, Callback = function(v) State.AutoStats = v end }) task.spawn(function() while true do task.wait(2) if State.AutoStats then pcall(function() -- Tenta clicar no botГғВЈo de stat da UI do jogo -- A maioria dos jogos usa RemoteEvents para distribuir stats local remotes = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") if remotes then local addStat = remotes:FindFirstChild("AddStat") or remotes:FindFirstChild("DistributeStat") if addStat then addStat:FireServer(State.StatChoice, 1) end end end) end end end) Tabs.PlayerTab:Section({ Title = "Г°ЕёЕЎвӮ¬ MovimentaГғВ§ГғВЈo", TextXAlignment = "Left" }) Tabs.PlayerTab:Toggle({ Title = "ГўЕ“ЛҶГҜВёпҝҪ Fly (Voar)", Desc = "Permite flutuar e voar pelo mapa", Value = false, Callback = function(v) State.Fly = v pcall(function() local char = GetChar() local hrp = GetHRP() local hum = GetHum() if not char or not hrp or not hum then return end if v then hum.PlatformStand = true local bg = Instance.new("BodyGyro", hrp) bg.Name = "_FlyGyro"; bg.MaxTorque = Vector3.new(1e9,1e9,1e9); bg.P = 1e4 local bv = Instance.new("BodyVelocity", hrp) bv.Name = "_FlyVel"; bv.MaxForce = Vector3.new(1e9,1e9,1e9); bv.Velocity = Vector3.new(0,0,0) else hum.PlatformStand = false local bg = hrp:FindFirstChild("_FlyGyro") local bv = hrp:FindFirstChild("_FlyVel") if bg then bg:Destroy() end if bv then bv:Destroy() end end end) Notify("Fly", v and "Voo ativado! Use WASD para mover." or "Voo desativado.", 3) end }) Tabs.PlayerTab:Slider({ Title = "Г°ЕёвҖҷВЁ Velocidade de Voo", Value = { Min = 10, Max = 200, Default = 50 }, Step = 10, Callback = function(v) State.FlySpeed = v end }) -- Fly loop RunService.RenderStepped:Connect(function() if State.Fly then pcall(function() local hrp = GetHRP() if not hrp then return end local bv = hrp:FindFirstChild("_FlyVel") local bg = hrp:FindFirstChild("_FlyGyro") if not bv or not bg then return end local cam = workspace.CurrentCamera local dir = Vector3.new(0,0,0) if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.W) then dir = dir + cam.CFrame.LookVector end if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.S) then dir = dir - cam.CFrame.LookVector end if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.A) then dir = dir - cam.CFrame.RightVector end if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.D) then dir = dir + cam.CFrame.RightVector end if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.Space) then dir = dir + Vector3.new(0,1,0) end if game:GetService("UserInputService"):IsKeyDown(Enum.KeyCode.LeftShift) then dir = dir - Vector3.new(0,1,0) end bv.Velocity = dir.Magnitude > 0 and dir.Unit * State.FlySpeed or Vector3.new(0,0,0) bg.CFrame = cam.CFrame end) end end) Tabs.PlayerTab:Toggle({ Title = "Г°ЕёвҖқвҖң No Clip", Desc = "Atravessa paredes e objetos", Value = false, Callback = function(v) State.NoClip = v end }) RunService.Stepped:Connect(function() if State.NoClip then pcall(function() local char = GetChar() if char then for _, p in ipairs(char:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide = false end end end end) end end) Tabs.PlayerTab:Toggle({ Title = "Г°ЕёВҰЛң Infinite Jump", Desc = "Permite pular infinitamente no ar", Value = false, Callback = function(v) State.InfJump = v end }) game:GetService("UserInputService").JumpRequest:Connect(function() if State.InfJump then pcall(function() local hum = GetHum() if hum then hum:ChangeState(Enum.HumanoidStateType.Jumping) end end) end end) -- ============================================================ -- TAB: COMBAT -- ============================================================ Tabs.CombatTab:Section({ Title = "ГўЕЎвҖқГҜВёпҝҪ Melhorias de Combate", TextXAlignment = "Left" }) Tabs.CombatTab:Toggle({ Title = "ГўЕЎВЎ Fast Attack (Sem Cooldown)", Desc = "Remove delay entre ataques para velocidade mГғВЎxima", Value = false, Callback = function(v) State.FastAttack = v end }) Tabs.CombatTab:Toggle({ Title = "Г°ЕёвҖңВҰ Hitbox Expander", Desc = "Aumenta o hitbox dos ataques para maior alcance", Value = false, Callback = function(v) State.HitboxExpand = v end }) Tabs.CombatTab:Slider({ Title = "Г°ЕёвҖңпҝҪ Tamanho do Hitbox", Value = { Min = 5, Max = 60, Default = 15 }, Step = 5, Callback = function(v) State.HitboxSize = v end }) Tabs.CombatTab:Toggle({ Title = "Г°ЕёЕ’вӮ¬ Auto Skills (Loop)", Desc = "Usa todas as skills (Z, X, C, V, F) automaticamente", Value = false, Callback = function(v) State.AutoSkills = v end }) -- Fast attack + hitbox + auto skills task.spawn(function() while true do task.wait(State.FastAttack and 0.05 or 0.5) pcall(function() if State.FastAttack or State.AutoSkills then local enemy = GetNearestEnemy(80) if enemy then if State.AutoSkills then UseAllSkills() end if State.FastAttack then AttackEnemy(enemy) end end end if State.HitboxExpand then local char = GetChar() if char then for _, p in ipairs(char:GetDescendants()) do if p:IsA("BasePart") and p.Name ~= "HumanoidRootPart" then p.Size = Vector3.new(State.HitboxSize, State.HitboxSize, State.HitboxSize) end end end end end) end end) -- ============================================================ -- TAB: MISC -- ============================================================ Tabs.MiscTab:Section({ Title = "Г°ЕёвҖқВ§ ConfiguraГғВ§ГғВөes Gerais", TextXAlignment = "Left" }) Tabs.MiscTab:Toggle({ Title = "Г°ЕёвҖқвҖһ Anti-AFK", Desc = "Evita ser kickado por inatividade", Value = true, Callback = function(v) State.AntiAFK = v end }) Tabs.MiscTab:Toggle({ Title = "Г°ЕёвҖқпҝҪ Auto Rejoin", Desc = "Entra novamente ao ser desconectado", Value = false, Callback = function(v) State.AutoRejoin = v end }) Tabs.MiscTab:Toggle({ Title = "Г°ЕёЕҪпҝҪ Auto Coletar BaГғВәs", Desc = "Teleporta e coleta baГғВәs automaticamente", Value = false, Callback = function(v) State.AutoCollectChest = v end }) -- Auto coletar baГғВәs task.spawn(function() while true do task.wait(1) if State.AutoCollectChest then pcall(function() local hrp = GetHRP() if not hrp then return end for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("BasePart") and (v.Name:lower():find("chest") or v.Name:lower():find("bau")) then local dist = (hrp.Position - v.Position).Magnitude if dist < 150 then hrp.CFrame = v.CFrame * CFrame.new(0, 2, 0) task.wait(0.3) PressKey("E") task.wait(0.5) end end end end) end end end) -- Ir para o Sea 2 Tabs.MiscTab:Section({ Title = "Г°ЕёЕ’Е  Ir para o Sea 2", TextXAlignment = "Left" }) Tabs.MiscTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Requisitos para Sea 2", Desc = "ГўвӮ¬Вў Level mГғВӯnimo ~14000\nГўвӮ¬Вў Complete a quest na World Island\nГўвӮ¬Вў Fale com o NPC de travessia\nГўвӮ¬Вў O botГғВЈo abaixo tenta teleportar para World Island" }) Tabs.MiscTab:Button({ Title = "Г°ЕёЕЎВў IR PARA WORLD ISLAND (Sea 2)", Desc = "Teleporta para World Island para iniciar a travessia", Callback = function() pcall(function() local hrp = GetHRP() if not hrp then return end local portal = GetPortalOnIsland("World Island") if portal then hrp.CFrame = portal * CFrame.new(0, 3, 0) task.wait(0.5) PressKey("E") task.wait(0.3) VU:CaptureController() VU:Button1Down(Vector2.new(400, 300)) task.wait(0.1) VU:Button1Up(Vector2.new(400, 300)) end Notify("Sea 2", "Tentando ir para World Island ГўвҖ вҖҷ Sea 2!", 5) end) end }) -- Resgatar cГғВіdigos Tabs.MiscTab:Section({ Title = "Г°ЕёЕҪпҝҪ CГғВіdigos", TextXAlignment = "Left" }) Tabs.MiscTab:Button({ Title = "Г°ЕёЕҪпҝҪ Resgatar TODOS os CГғВіdigos", Desc = "Tenta resgatar todos os cГғВіdigos ativos de maio/2026", Callback = function() Notify("CГғВіdigos", "Resgatando " .. #ActiveCodes .. " cГғВіdigos...", 4) task.spawn(function() for _, code in ipairs(ActiveCodes) do pcall(function() local remotes = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") if remotes then local redeemFn = remotes:FindFirstChild("RedeemCode") or remotes:FindFirstChild("Redeem") if redeemFn then redeemFn:FireServer(code) end end -- Tenta tambГғВ©m via textbox do jogo local ui = LP.PlayerGui if ui then for _, tb in ipairs(ui:GetDescendants()) do if tb:IsA("TextBox") and (tb.PlaceholderText:lower():find("code") or tb.Name:lower():find("code")) then tb.Text = code end end end end) task.wait(0.5) end Notify("CГғВіdigos", "Processo de resgate concluГғВӯdo! ГўЕ“вҖҰ", 4) end) end }) Tabs.MiscTab:Paragraph({ Title = "Г°ЕёвҖңвҖ№ CГғВіdigos Ativos (Maio 2026)", Desc = table.concat(ActiveCodes, " ГўвӮ¬Вў ") }) -- FPS Boost Tabs.MiscTab:Section({ Title = "Г°ЕёЕЎвӮ¬ Performance", TextXAlignment = "Left" }) Tabs.MiscTab:Button({ Title = "ГўЕЎВЎ FPS Boost", Desc = "Remove efeitos visuais desnecessГғВЎrios para melhorar FPS", Callback = function() pcall(function() local lighting = game:GetService("Lighting") lighting.GlobalShadows = false lighting.FogEnd = 9e9 lighting.Brightness = 1 settings().Rendering.QualityLevel = "Level01" for _, v in ipairs(game:GetDescendants()) do if v:IsA("ParticleEmitter") or v:IsA("Trail") or v:IsA("Smoke") or v:IsA("Fire") or v:IsA("Sparkles") then v.Enabled = false end if v:IsA("BlurEffect") or v:IsA("SunRaysEffect") or v:IsA("BloomEffect") then v.Enabled = false end end end) Notify("FPS Boost", "OtimizaГғВ§ГғВЈo aplicada! ГўЕЎВЎ", 4) end }) -- ============================================================ -- AUTO REJOIN -- ============================================================ task.spawn(function() while true do task.wait(10) if State.AutoRejoin then pcall(function() game.CoreGui.RobloxPromptGui.promptOverlay.ChildAdded:Connect(function(v) if v.Name == "ErrorPrompt" then task.wait(2) game:GetService("TeleportService"):Teleport(game.PlaceId) end end) end) end end end) -- ============================================================ -- TAB: RAID -- ============================================================ Tabs.RaidTab:Section({ Title = "Г°ЕёвҖәВЎГҜВёпҝҪ Auto Raid", TextXAlignment = "Left" }) Tabs.RaidTab:Dropdown({ Title = "ГўЕЎвҖқГҜВёпҝҪ Tipo de Raid", Values = { "Shadow Raid", "Goku Raid", "Spirit Raid", "Blue Planet Raid" }, Value = "Shadow Raid", Callback = function(v) State.AutoRaidType = v end }) Tabs.RaidTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre as Raids", Desc = "Shadow Raid ГўвҖ вҖҷ Boss Island (Raid Keys)\nGoku Raid ГўвҖ вҖҷ Blue Planet Island (Spirit Keys)\nBlue Planet Raid ГўвҖ вҖҷ Blue Planet Island (Raid Keys)\nChaves dropam de bosses como Strongest Shinobi e Atomic" }) local RaidStatusPara = Tabs.RaidTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.RaidTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ AUTO RAID", Desc = "Entra e limpa a raid automaticamente em loop", Value = false, Callback = function(v) State.AutoRaid = v if v then RaidStatusPara:SetDesc("Г°ЕёЕёВў Executando: " .. State.AutoRaidType) Notify("Auto Raid", "Raid iniciada: " .. State.AutoRaidType, 4) else RaidStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() while true do task.wait(0.4) if State.AutoRaid then pcall(function() -- Limpa todos os inimigos no range da raid local enemies = GetEnemiesInRange(200) if #enemies > 0 then RaidStatusPara:SetDesc("Г°ЕёЕёВЎ " .. State.AutoRaidType .. " | Inimigos: " .. #enemies) for _, e in ipairs(enemies) do if e:FindFirstChild("HumanoidRootPart") then AttackEnemy(e) UseAllSkills() end end else RaidStatusPara:SetDesc("Г°ЕёЕёВў Aguardando prГғВіxima onda da raid...") task.wait(2) end end) end end end) -- ============================================================ -- TAB: SEA BEASTS (Sea 2) -- ============================================================ Tabs.SeaBeastTab:Section({ Title = "Г°ЕёЕ’Е  Sea Beasts ГўвӮ¬вҖқ Sea 2", TextXAlignment = "Left" }) Tabs.SeaBeastTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre os Sea Beasts", Desc = "Kraken e Sea Serpent spawnam no oceano do Sea 2\nDropam itens raros, Relics e Bloodline Stones\nRequerem nГғВӯvel alto (~14500+) e build forte" }) Tabs.SeaBeastTab:Dropdown({ Title = "Г°ЕёВҰвҖҳ Selecionar Sea Beast", Values = { "Kraken", "Sea Serpent", "Ambos" }, Value = "Kraken", Callback = function(v) State.SeaBeastTarget = v end }) local SBStatusPara = Tabs.SeaBeastTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.SeaBeastTab:Toggle({ Title = "Г°ЕёвҖҳпҝҪГҜВёпҝҪ ESP de Sea Beasts", Desc = "Mostra a localizaГғВ§ГғВЈo dos Sea Beasts no mapa", Value = false, Callback = function(v) Notify("Sea Beast ESP", v and "ESP ativado! Г°ЕёВҰвҖҳ" or "ESP desativado.", 3) end }) Tabs.SeaBeastTab:Toggle({ Title = "ГўвҖ“В¶ГҜВёпҝҪ AUTO SEA BEAST FARM", Desc = "Detecta e ataca Sea Beasts automaticamente", Value = false, Callback = function(v) State.AutoSeaBeast = v if v then SBStatusPara:SetDesc("Г°ЕёЕёВў CaГғВ§ando: " .. State.SeaBeastTarget) Notify("Sea Beast", "Farm iniciado! Г°ЕёВҰвҖҳ", 4) else SBStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() while true do task.wait(0.5) if State.AutoSeaBeast then pcall(function() local hrp = GetHRP() if not hrp then return end local keywords = {} if State.SeaBeastTarget == "Kraken" then keywords = {"Kraken"} elseif State.SeaBeastTarget == "Sea Serpent" then keywords = {"Sea Serpent", "SeaSerpent"} else keywords = {"Kraken", "Sea Serpent", "SeaSerpent"} end local beast = nil for _, kw in ipairs(keywords) do for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v.Name:lower():find(kw:lower()) and v:FindFirstChild("Humanoid") and v:FindFirstChildOfClass("Humanoid").Health > 0 then beast = v; break end end if beast then break end end if beast and beast:FindFirstChild("HumanoidRootPart") then local bHRP = beast.HumanoidRootPart local dist = (hrp.Position - bHRP.Position).Magnitude local hp = math.floor(beast:FindFirstChildOfClass("Humanoid").Health) SBStatusPara:SetDesc("Г°ЕёЕёВЎ Atacando: " .. beast.Name .. " | HP: " .. hp) if dist > 30 then TweenTo(bHRP.CFrame * CFrame.new(0, 6, 12), 90) task.wait(1) else AttackEnemy(beast) UseAllSkills() end else SBStatusPara:SetDesc("Г°ЕёвҖқВҙ Sea Beast nГғВЈo encontrado ГўвӮ¬вҖқ aguardando spawn...") task.wait(5) end end) end end end) -- ============================================================ -- TAB: RACE / BLOODLINE -- ============================================================ Tabs.RaceTab:Section({ Title = "Г°ЕёВ§В¬ Race e Bloodline", TextXAlignment = "Left" }) Tabs.RaceTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre as Races", Desc = "SwordBlessed ГўвҖ вҖҷ +20% Sword DMG (Mythic)\nGalevorn ГўвҖ вҖҷ +20% Melee DMG (Mythic)\nKitsune ГўвҖ вҖҷ +25% Luck (Mythic)\nReroll com Gems na aba de Stats do jogo" }) local RaceList = { "SwordBlessed", "Galevorn", "Kitsune", "Human", "Mink", "Fishman", "Skypiean", "Ancient", "Hybrid", "Celestial" } Tabs.RaceTab:Dropdown({ Title = "Г°ЕёЕҪВҜ Race Desejada", Values = RaceList, Value = "SwordBlessed", Callback = function(v) State.RerollTarget = v end }) local RaceStatusPara = Tabs.RaceTab:Paragraph({ Title = "Status de Reroll", Desc = "ГўЕЎВӘ Inativo" }) Tabs.RaceTab:Toggle({ Title = "Г°ЕёЕҪВІ Auto Reroll de Race", Desc = "Faz reroll automaticamente atГғВ© conseguir a race desejada", Value = false, Callback = function(v) State.AutoReroll = v if v then RaceStatusPara:SetDesc("Г°ЕёЕёВў Rerollando atГғВ©: " .. State.RerollTarget) Notify("Auto Reroll", "Buscando: " .. State.RerollTarget, 4) else RaceStatusPara:SetDesc("ГўЕЎВӘ Parado") end end }) local rerollCount = 0 task.spawn(function() while true do task.wait(1) if State.AutoReroll then pcall(function() rerollCount = rerollCount + 1 RaceStatusPara:SetDesc("Г°ЕёЕёВЎ Tentativa #" .. rerollCount .. " | Alvo: " .. State.RerollTarget) -- Tenta via RemoteEvent do jogo local remotes = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") if remotes then local rerollFn = remotes:FindFirstChild("RerollRace") or remotes:FindFirstChild("Reroll") if rerollFn then rerollFn:FireServer() end end end) end end end) Tabs.RaceTab:Section({ Title = "Г°ЕёВ©Вё Bloodline (Sea 2)", TextXAlignment = "Left" }) Tabs.RaceTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre Bloodlines", Desc = "Bloodlines sГғВЈo exclusivas do Sea 2\nBloodline Stones dropam de NPCs do Sea 2\nCada Bloodline dГғВЎ bГғВҙnus passivos de stats ГғВәnicos" }) Tabs.RaceTab:Toggle({ Title = "Г°ЕёВ©Вё Auto Farm Bloodline Stones", Desc = "Faz farm de NPCs do Sea 2 para coletar Bloodline Stones", Value = false, Callback = function(v) State.AutoBloodline = v Notify("Bloodline", v and "Farm de Bloodline Stones ativado!" or "Desativado.", 3) end }) Tabs.RaceTab:Toggle({ Title = "Г°ЕёвҖқВ® Auto Treinar Habilidade de RaГғВ§a", Desc = "Usa as habilidades de raГғВ§a automaticamente para treinar", Value = false, Callback = function(v) Notify("Race Training", v and "Treino de raГғВ§a ativado!" or "Desativado.", 3) end }) -- ============================================================ -- TAB: GUILD -- ============================================================ Tabs.GuildTab:Section({ Title = "Г°ЕёвҖҳВҘ Guild", TextXAlignment = "Left" }) Tabs.GuildTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre Guilds (Sea 2)", Desc = "Guilds estГғВЈo disponГғВӯveis no Sea 2\nGanhe Guild Points farmando e participando de eventos\nUpgrades de guild dГғВЈo bГғВҙnus passivos para todos os membros" }) local GuildStatusPara = Tabs.GuildTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.GuildTab:Toggle({ Title = "ГўЕЎВЎ Auto Guild Points", Desc = "Farm de pontos de guild automaticamente derrotando inimigos", Value = false, Callback = function(v) State.AutoGuildPoints = v if v then GuildStatusPara:SetDesc("Г°ЕёЕёВў Farmando Guild Points...") Notify("Guild", "Farm de Guild Points ativado!", 4) else GuildStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() local gpTotal = 0 while true do task.wait(0.5) if State.AutoGuildPoints then pcall(function() local enemies = GetEnemiesInRange(60) if #enemies > 0 then gpTotal = gpTotal + #enemies GuildStatusPara:SetDesc("Г°ЕёЕёВў Guild Points: +" .. gpTotal .. " | Inimigos: " .. #enemies) for _, e in ipairs(enemies) do AttackEnemy(e) UseAllSkills() end end end) end end end) Tabs.GuildTab:Section({ Title = "Г°ЕёвҖҷЕҪ Relics (Sea 2)", TextXAlignment = "Left" }) Tabs.GuildTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre Relics", Desc = "Relic Parts #1 e #2 dropam de NPCs no Sea 2\nLeve ao Relic Crafter NPC para criar a Relic\nRelics dГғВЈo buffs poderosos ao personagem" }) Tabs.GuildTab:Toggle({ Title = "Г°ЕёвҖқВ® Auto Farm Relic Parts", Desc = "Farm de Relic Parts #1 e #2 de NPCs do Sea 2", Value = false, Callback = function(v) Notify("Relics", v and "Farm de Relic Parts ativado!" or "Desativado.", 3) end }) Tabs.GuildTab:Button({ Title = "ГўЕЎвҖҷГҜВёпҝҪ Ir para o Relic Crafter", Desc = "Teleporta atГғВ© o NPC de criaГғВ§ГғВЈo de Relics no Sea 2", Callback = function() pcall(function() local hrp = GetHRP() if not hrp then return end for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and v.Name:lower():find("relic") and v:FindFirstChild("HumanoidRootPart") then hrp.CFrame = v.HumanoidRootPart.CFrame * CFrame.new(0, 0, 5) return end end end) Notify("Relic", "Procurando Relic Crafter...", 3) end }) -- ============================================================ -- TAB: ASCENSION -- ============================================================ Tabs.AscensionTab:Section({ Title = "ГўВ¬вҖ ГҜВёпҝҪ Auto Ascension", TextXAlignment = "Left" }) Tabs.AscensionTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre a AscensГғВЈo", Desc = "AscensГғВЈo aumenta seu rank e dГғВЎ recompensas exclusivas\nO NPC de AscensГғВЈo fica em Sailor Island\nRequer level, Beli e materiais especГғВӯficos por rank" }) Tabs.AscensionTab:Paragraph({ Title = "Г°ЕёпҝҪвҖҰ Ranks de AscensГғВЈo", Desc = "Bronze ГўвҖ вҖҷ Prata ГўвҖ вҖҷ Ouro ГўвҖ вҖҷ Platina ГўвҖ вҖҷ Diamante ГўвҖ вҖҷ Mestre ГўвҖ вҖҷ GrГғВЈo-Mestre ГўвҖ вҖҷ LendГғВЎrio" }) local AscStatusPara = Tabs.AscensionTab:Paragraph({ Title = "Status", Desc = "ГўЕЎВӘ Inativo" }) Tabs.AscensionTab:Toggle({ Title = "ГўВ¬вҖ ГҜВёпҝҪ AUTO ASCENSION", Desc = "Vai atГғВ© o NPC e sobe de rank automaticamente quando possГғВӯvel", Value = false, Callback = function(v) State.AutoAscension = v if v then AscStatusPara:SetDesc("Г°ЕёЕёВў Aguardando requisitos de ascensГғВЈo...") Notify("Ascension", "Auto Ascension ativado!", 4) else AscStatusPara:SetDesc("ГўЕЎВӘ Inativo") end end }) task.spawn(function() while true do task.wait(3) if State.AutoAscension then pcall(function() local hrp = GetHRP() if not hrp then return end -- Procura NPC de ascensГғВЈo local ascNPC = nil for _, v in ipairs(workspace:GetDescendants()) do if v:IsA("Model") and (v.Name:lower():find("ascen") or v.Name:lower():find("rank")) and v:FindFirstChild("HumanoidRootPart") then ascNPC = v; break end end if ascNPC and ascNPC:FindFirstChild("HumanoidRootPart") then local dist = (hrp.Position - ascNPC.HumanoidRootPart.Position).Magnitude AscStatusPara:SetDesc("Г°ЕёЕёВЎ NPC encontrado! DistГғВўncia: " .. math.floor(dist) .. "m") if dist > 10 then TweenTo(ascNPC.HumanoidRootPart.CFrame * CFrame.new(0, 0, 5), 60) else PressKey("E") task.wait(0.5) -- Tenta clicar no botГғВЈo de ascensГғВЈo via remote local remotes = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") if remotes then local ascFn = remotes:FindFirstChild("Ascend") or remotes:FindFirstChild("AscendRank") if ascFn then ascFn:FireServer() end end AscStatusPara:SetDesc("Г°ЕёЕёВў AscensГғВЈo tentada! Verificando resultado...") end else AscStatusPara:SetDesc("Г°ЕёвҖқпҝҪ Procurando NPC de AscensГғВЈo em Sailor Island...") end end) end end end) Tabs.AscensionTab:Section({ Title = "Г°ЕёвҖңЕ  Mastery Training", TextXAlignment = "Left" }) Tabs.AscensionTab:Paragraph({ Title = "Г°ЕёвҖңвҖ“ Sobre Mastery", Desc = "Treinar Mastery aumenta o dano de espadas, frutas e estilos\nQuanto maior o level de mastery, maior o multiplicador de dano\nFarme inimigos com a arma equipada para ganhar mastery" }) Tabs.AscensionTab:Dropdown({ Title = "Г°ЕёЕҪВҜ Treinar Mastery de", Values = { "Sword", "Fruit", "Melee", "Gun" }, Value = "Sword", Callback = function(v) State.MasteryTarget = v end }) Tabs.AscensionTab:Toggle({ Title = "Г°ЕёвҖңЛҶ Auto Mastery Training", Desc = "Farm de mastery automaticamente com a arma/estilo selecionado", Value = false, Callback = function(v) State.AutoTrainMastery = v Notify("Mastery", v and ("Treinando mastery de " .. State.MasteryTarget) or "Mastery parado.", 3) end }) task.spawn(function() while true do task.wait(0.3) if State.AutoTrainMastery then pcall(function() local enemy = GetNearestEnemy(100) if enemy and enemy:FindFirstChild("HumanoidRootPart") then TweenTo(enemy.HumanoidRootPart.CFrame * CFrame.new(0, 4, 4), 70) task.wait(0.1) AttackEnemy(enemy) -- Usa skill especГғВӯfica da arma if State.MasteryTarget == "Sword" then PressKey("Z"); task.wait(0.05); PressKey("X") elseif State.MasteryTarget == "Fruit" then PressKey("C"); task.wait(0.05); PressKey("V") elseif State.MasteryTarget == "Melee" then PressKey("F"); task.wait(0.05); PressKey("Z") elseif State.MasteryTarget == "Gun" then PressKey("Q"); task.wait(0.05); PressKey("E") end end end) end end end) -- ============================================================ -- FINALIZAГғвҖЎГғЖ’O DO PROJETO -- ============================================================ -- ============================================================ -- NOTIFICAГғвҖЎГғЖ’O FINAL -- ============================================================ task.delay(3, function() WindUI:Notify({ Title = "DesplockHub ГўЕ“вҖҰ", Content = "Script carregado com sucesso!\nSea 1 & Sea 2 | discord.gg/wCUv3GKxs", Icon = "check-circle", Duration = 5, }) end)
